const client = $input.item.json;
const keywords = client.keywords || [];
const queries = [];

const templates = [
  '"write for us" + {kw}',
  '"guest post" + {kw}',
  '"submit article" + {kw}',
  '"contribute" + {kw} + blog',
  '"accepting guest posts" + {kw}',
  'inurl:write-for-us {kw}',
  'intitle:"guest post guidelines" {kw}',
  '{kw} + "become a contributor"',
  '{kw} + resource page + link',
  '{kw} + roundup + blog'
];

for (const kw of keywords.slice(0, 5)) {
  for (const tmpl of templates.slice(0, 3)) {
    queries.push({
      json: {
        client_id: client.client_id,
        domain: client.domain,
        query: tmpl.replace('{kw}', kw),
        keyword: kw
      }
    });
  }
}

return queries.length > 0 ? queries : [{ json: { client_id: client.client_id, domain: client.domain, query: '"write for us" + ' + client.domain.split('.')[0], keyword: client.domain.split('.')[0] } }];

const query = $('Batch Queries').item.json;
const results = $input.item.json;
const items = results.items || [];
const prospects = [];

for (const item of items) {
  const url = item.link || '';
  const domain = url.replace(/^https?:\/\//, '').split('/')[0];

  // Skip the client's own domain
  if (domain.includes(query.domain)) continue;

  prospects.push({
    json: {
      client_id: query.client_id,
      domain: domain,
      url: url,
      title: item.title || '',
      snippet: (item.snippet || '').substring(0, 200),
      keyword: query.keyword,
      source: 'n8n-prospector'
    }
  });
}

return prospects.length > 0 ? prospects : [{ json: { skip: true } }];
